func (c *current) onSQLBodySetOp1(first, rest any) (any, error) {
	out := first.(ast.SQLQueryBody)
	for _, o := range rest.([]any) {
		o := o.([]any)
		right := o[2].(ast.SQLQueryBody)
		out = &ast.SQLUnion{
			Kind:     "SQLUnion",
			Distinct: o[0].(bool),
			Left:     out,
			Right:    right,
			Loc:      ast.Loc{First: out.Pos(), Last: right.End()},
		}
	}
	return out, nil

}

